targets.expr:
sort(
  1 / (
    avg by (provider) (
      (
        1 / avg by (provider, source_region) (
          avg_over_time(
            (response_latency_seconds{blockchain="Base", response_status="success"} > 0)[$__range:$__interval]
          )
        )
      )
      *
      (
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="Base", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="Base"} > 0)[$__range:$__interval]))
        )
        *
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="Base", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="Base"} > 0)[$__range:$__interval]))
        )
        *
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="Base", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="Base"} > 0)[$__range:$__interval]))
        )
      )
    )
  )
)

avg by (provider, source_region) (
  avg_over_time(
    (response_latency_seconds{blockchain="Base", response_status="success", source_region=~"fra1|sfo1|hnd1"} > 0)[$__range:$__interval]
  )
)

avg by (provider, api_method) (
  avg_over_time(
    (response_latency_seconds{blockchain="Base", response_status="success"} >= 0)[$__range:$__interval]
  )
)

avg by (provider, api_method, source_region) (
  avg_over_time(
    (response_latency_seconds{blockchain="Base", response_status="success", api_method=~"(eth_call|eth_getBalance)", source_region=~"fra1|sfo1|hnd1"} 
      >= 0
    )[$__range:$__interval]
))

avg by (provider, api_method, source_region) (
  avg_over_time(
    (response_latency_seconds{blockchain="Base", response_status="success", api_method=~"(eth_blockNumber|eth_getTransactionReceipt|eth_getLogs)", source_region=~"fra1|sfo1|hnd1"} 
      >= 0
    )[$__range:$__interval]
))

avg by (provider, api_method, source_region) (
  avg_over_time(
    (response_latency_seconds{blockchain="Base", response_status="success", api_method=~"(.*debug.*|eth_subscribe)", source_region=~"fra1|sfo1|hnd1"} 
      >= 0
    )[$__range:$__interval]
))
